package org.eclipse.rdf4j.sail.base;

import static org.assertj.core.api.Assertions.assertThat;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinOrderPlanner;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.slf4j.LoggerFactory;

import ch.qos.logback.classic.Level;
import ch.qos.logback.classic.Logger;
import ch.qos.logback.classic.spi.ILoggingEvent;
import ch.qos.logback.core.read.ListAppender;

class SketchJoinOrderPlannerLoggingTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	private Logger plannerLogger;
	private Logger reordererLogger;
	private Level originalPlannerLevel;
	private Level originalReordererLevel;
	private ListAppender<ILoggingEvent> listAppender;

	@BeforeEach
	void attachAppender() {
		plannerLogger = (Logger) LoggerFactory.getLogger(SketchJoinOrderPlanner.class);
		reordererLogger = (Logger) LoggerFactory.getLogger(SketchJoinOrderReorderer.class);
		originalPlannerLevel = plannerLogger.getLevel();
		originalReordererLevel = reordererLogger.getLevel();
		listAppender = new ListAppender<>();
		listAppender.start();
		plannerLogger.setLevel(Level.DEBUG);
		reordererLogger.setLevel(Level.DEBUG);
		plannerLogger.addAppender(listAppender);
		reordererLogger.addAppender(listAppender);
	}

	@AfterEach
	void detachAppender() {
		plannerLogger.detachAppender(listAppender);
		reordererLogger.detachAppender(listAppender);
		plannerLogger.setLevel(originalPlannerLevel);
		reordererLogger.setLevel(originalReordererLevel);
	}

	@Test
	void debugLoggingExplainsGreedyReorderDecision() {
		StubSailStore store = new StubSailStore();
		IRI pA = VF.createIRI("urn:pA");
		IRI pB = VF.createIRI("urn:pB");
		IRI y = VF.createIRI("urn:y");

		for (int i = 0; i < 512; i++) {
			Resource s = VF.createIRI("urn:s" + i);
			IRI x = VF.createIRI("urn:x" + i);
			store.add(VF.createStatement(s, pA, x));
		}
		store.add(VF.createStatement(VF.createIRI("urn:x0"), pB, y));

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuildOnceSlow();

		StatementPattern a = pattern("s", pA, "x");
		StatementPattern b = pattern("x", pB, "y");
		List<TupleExpr> args = List.of(a, b);

		assertTrue(estimator.planJoinOrder(args, Set.of(), JoinOrderPlanner.Algorithm.GREEDY).isPresent());

		String logOutput = listAppender.list.stream()
				.map(ILoggingEvent::getFormattedMessage)
				.collect(Collectors.joining("\n"));

		assertThat(logOutput)
				.contains("Sketch join reorder input:")
				.contains("originalOrder=")
				.contains("factor[0]")
				.contains("factor[1]")
				.contains("greedy seed")
				.contains("greedy candidate")
				.contains("greedy choose")
				.contains("result: order=")
				.contains("outputRows=")
				.contains("workRows=")
				.contains("SP(?x urn:pB ?y)");
	}

	private static StatementPattern pattern(String subjVar, IRI predicate, String objVar) {
		return new StatementPattern(Var.of(subjVar), Var.of("p", predicate), Var.of(objVar));
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}
}
